#define _POSIX_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>

int main(int argc, char*argv[]){
union sigval sigVal;

}编译器报错： incomplete type is not allowed

这个问题可能是因为在代码中没有包含必要的头文件，或者缺少必要的定义导致的。`union sigval` 是在 `<signal.h>` 中定义的，因此需要包含 `<signal.h>` 头文件。

下面是已经修正了这个问题的代码示例：
```
#define _POSIX_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>

int main(int argc, char*argv[]){
    union sigval sigVal;
    // 使用 sigVal 进行操作
    return 0;
}
```
在这个示例中，已经包含了 `<signal.h>` 头文件，因此可以使用 `union sigval` 类型了。

如果你仍然收到 `incomplete type is not allowed` 编译错误，可能是因为你的编译器不支持 C11 标准或 POSIX 标准所定义的 `union sigval` 数据类型。在这种情况下，你可能需要手动定义一个 `union sigval` 类型，或者使用其他与 `union sigval` 类型功能相似的数据类型。

以下是手动定义 `union sigval` 类型的示例：
```
#define _POSIX_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>

// 手动定义 union sigval 类型
union sigval {
    int sival_int;
    void *sival_ptr;
};

int main(int argc, char*argv[]){
    union sigval sigVal;
    // 使用 sigVal 进行操作
    return 0;
}
```
在这个示例中，我们手动定义了 `union sigval` 类型，并对其进行了操作。这样，即使编译器不支持 POSIX 标准所定义的 `union sigval` 数据类型，也可以正常编译和运行代码。

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main(void)
{
    pid_t pid;
    pid = fork();
    switch (pid) {
    case -1:
        perror("fork error");
        exit(-1);
    case 0:
        printf("这是子进程打印信息<pid: %d, 父进程 pid: %d>\n",
        getpid(), getppid());
        _exit(0); //子进程使用_exit()退出
    default:
        printf("这是父进程打印信息<pid: %d, 子进程 pid: %d>\n",
        getpid(), pid);
        exit(0);
 }

} 程序如何运行
